#include <iostream>using namespace std; int pre[1000001];int nxt[1000001];int cnt[1000001];int head; int main(){	ios::sync_with_stdio(0);	cin.tie(0);		int n,q;	cin>>n>>q;		for(int i=1;i<=1000000;i++)	{		pre[i]=0;		nxt[i]=0;		cnt[i]=0;	}		head=0;		for(int i=0;i<n;i++)	{		int x;		cin>>x;		cnt[x]++;		if(cnt[x]==1)		{			if(head==0)			{				head=x;			}			else			{				int p=head;				while(nxt[p]!=0&&nxt[p]<x)				{					p=nxt[p];				}				nxt[x]=nxt[p];				pre[x]=p;				if(nxt[p]!=0)				{					pre[nxt[p]]=x;				}				nxt[p]=x;			}		}	}		while(q--)	{		int k;		cin>>k;		if(k>0)		{			int x=k;			cnt[x]++;			if(cnt[x]==1)			{				if(head==0)				{					head=x;				}				else				{					int p=head;					while(nxt[p]!=0&&nxt[p]<x)					{						p=nxt[p];					}					nxt[x]=nxt[p];					pre[x]=p;					if(nxt[p]!=0)					{						pre[nxt[p]]=x;					}					nxt[p]=x;				}			}		}		else		{			int t=-k;			int p=head;			while(1)			{				if(cnt[p]>=t)				{					cnt[p]--;					if(cnt[p]==0)					{						if(pre[p]==0)						{							head=nxt[p];						}						else						{							nxt[pre[p]]=nxt[p];						}						if(nxt[p]!=0)						{							pre[nxt[p]]=pre[p];						}					}					break;				}				else				{					t-=cnt[p];					p=nxt[p];				}			}		}	}		if(head!=0)	{		cout<<head;	}	else	{		cout<<0;	}		return 0;}